proof fn phi_1_fold_left_sum_le_empty<A>(init: int, high: int, f: spec_fn(A) -> int)
    ensures
        Seq::<A>::empty().fold_left(init, |acc: int, x: A| acc + f(x)) <= init,
{
    lemma_seq_fold_left_sum_le(Seq::<A>::empty(), init, high, f);
}

proof fn phi_2_fold_left_sum_le_negative_high<A>(s: Seq<A>, init: int, f: spec_fn(A) -> int)
    requires
        s.len() > 0,
        forall |i: int| 0 <= i < s.len() ==> f(s[i]) <= -1,
    ensures
        s.fold_left(init, |acc: int, x: A| acc + f(x)) <= init - s.len(),
{
    lemma_seq_fold_left_sum_le(s, init, -1, f);
    assert(init + s.len() * (-1int) == init - s.len()) by (nonlinear_arith);
}

proof fn phi_3_fold_left_sum_le_zero_values<A>(s: Seq<A>, init: int, f: spec_fn(A) -> int)
    requires
        s.len() > 0,
        forall |i: int| 0 <= i < s.len() ==> f(s[i]) <= 0,
    ensures
        s.fold_left(init, |acc: int, x: A| acc + f(x)) <= init,
{
    lemma_seq_fold_left_sum_le(s, init, 0, f);
}

proof fn phi_4_fold_left_sum_le_high_much_larger<A>(s: Seq<A>, init: int, f: spec_fn(A) -> int)
    requires
        s.len() > 0,
        forall |i: int| 0 <= i < s.len() ==> f(s[i]) <= 0,
    ensures
        s.fold_left(init, |acc: int, x: A| acc + f(x)) <= init + s.len() * 1000000,
{
    lemma_seq_fold_left_sum_le(s, init, 1000000, f);
}

proof fn phi_5_fold_left_sum_le_singleton<A>(a: A, init: int, high: int, f: spec_fn(A) -> int)
    requires
        f(a) <= high,
    ensures
        seq![a].fold_left(init, |acc: int, x: A| acc + f(x)) <= init + high,
{
    lemma_seq_fold_left_sum_le(seq![a], init, high, f);
}
